module register (
    input [7:0] d,
    input clk,
    input reset,
    output reg [7:0] q
);

    // 8-bit register logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or posedge dbg_halt) begin
        if (~reset)
            q <= 8'b00000000;
        else
            q <= d;
    end

endmodule
